import numpy as np

def gelu(x: np.ndarray) -> np.ndarray:
    return 0.5 * x * (1.0 + np.tanh(np.sqrt(2.0 / np.pi) * (x + 0.044715 * x ** 3)))

def ffn(
    x: np.ndarray,
    W1: np.ndarray,
    b1: np.ndarray,
    W2: np.ndarray,
    b2: np.ndarray
) -> np.ndarray:
    h = gelu(x @ W1 + b1)  # (..., d_ff)
    return h @ W2 + b2      # (..., d_model)
